                  <textarea className="coach-input" placeholder="Es: Obiettivo massa muscolare. Problemi alla spalla destra. Allena lun/mer/ven." value={nuovoCliente.note} onChange={e=>setNuovoCliente(p=>({...p,note:e.target.value}))} style={{resize:"vertical",minHeight:80}}/>
